public class Main {
    static class Node {
        int data;
        Node next;
        Node(int data) { this.data = data; }
    }

    static Node last; // keep a reference to the LAST node for convenience

    static void insertAtEnd(int data) {
        Node newNode = new Node(data);
        if (last == null) {
            last = newNode;
            newNode.next = newNode; // points to itself -- a circle of one
            return;
        }
        newNode.next = last.next; // new node points to the current first node
        last.next = newNode;      // old last points to the new node
        last = newNode;           // new node becomes the last node
    }

    static void printList() {
        if (last == null) return;
        Node first = last.next;
        Node current = first;
        do {
            System.out.print(current.data + " ");
            current = current.next;
        } while (current != first);
        System.out.println();
    }

    public static void main(String[] args) {
        insertAtEnd(10);
        insertAtEnd(20);
        insertAtEnd(30);
        printList();
    }
}

