class Solution {
    public Node insert(Node head, int insertVal) {
        if (head == null) {
            Node newNode = new Node(insertVal);
            newNode.next = newNode;
            return newNode;
        }

        java.util.List<Integer> values = new java.util.ArrayList<>();
        Node current = head;
        do {
            values.add(current.val);
            current = current.next;
        } while (current != head);

        values.add(insertVal);
        java.util.Collections.sort(values);

        Node dummy = new Node(0);
        Node tail = dummy;
        for (int v : values) {
            tail.next = new Node(v);
            tail = tail.next;
        }
        tail.next = dummy.next; // close the circle
        return dummy.next;
    }
}

class Node {
    int val;
    Node next;
    Node(int val) { this.val = val; }
}

class Solution {
    public Node insert(Node head, int insertVal) {
        Node newNode = new Node(insertVal);

        if (head == null) {
            newNode.next = newNode;
            return newNode;
        }

        Node prev = head;
        Node current = head.next;

        while (current != head) {
            if (prev.val <= insertVal && insertVal <= current.val) {
                break; // normal case -- fits between prev and current
            }
            if (prev.val > current.val) { // wrap point (max-to-min transition)
                if (insertVal >= prev.val || insertVal <= current.val) {
                    break;
                }
            }
            prev = current;
            current = current.next;
        }

        prev.next = newNode;
        newNode.next = current;
        return head;
    }
}

